import java.time.LocalDate;
import java.time.LocalTime;
import java.time.LocalDateTime;

// 現在の日付・時刻
LocalDate today = LocalDate.now();
LocalTime now = LocalTime.now();
LocalDateTime dateTime = LocalDateTime.now();

System.out.println(today);    // 例: 2024-04-01
System.out.println(now);      // 例: 14:30:15.123
System.out.println(dateTime); // 例: 2024-04-01T14:30:15.123

// イミュータブルの確認
LocalDate d = LocalDate.of(2024, 1, 1);
d.plusDays(10);  // 戻り値を受け取っていない！
System.out.println(d); // 2024-01-01（変更されない）

LocalDate d2 = d.plusDays(10); // 新しいインスタンスを受け取る
System.out.println(d2); // 2024-01-11

import java.time.*;

// of()メソッド
LocalDate d1 = LocalDate.of(2024, 3, 15);       // int指定
LocalDate d2 = LocalDate.of(2024, Month.MARCH, 15); // Month enum
LocalTime t1 = LocalTime.of(14, 30);             // 時, 分
LocalTime t2 = LocalTime.of(14, 30, 45);         // 時, 分, 秒
LocalDateTime dt1 = LocalDateTime.of(2024, 3, 15, 14, 30);

// LocalDate + LocalTimeから生成
LocalDateTime dt2 = LocalDateTime.of(d1, t1);

// parse()メソッド
LocalDate d3 = LocalDate.parse("2024-03-15");
LocalTime t3 = LocalTime.parse("14:30:45");
LocalDateTime dt3 = LocalDateTime.parse("2024-03-15T14:30:45");

// 不正な値 → DateTimeException
try {
    LocalDate invalid = LocalDate.of(2024, 13, 1); // 月が13
} catch (DateTimeException e) {
    System.out.println(e.getMessage());
}

// Month enumの使用
Month m = Month.APRIL;
System.out.println(m.getValue()); // 4
System.out.println(m.name());     // APRIL

// Month enumから日数を取得
System.out.println(Month.FEBRUARY.length(false)); // 28（平年）
System.out.println(Month.FEBRUARY.length(true));  // 29（閏年）

// new は使えない
// LocalDate d = new LocalDate(); // コンパイルエラー

