import java.time.LocalDate;
import java.time.LocalTime;
import java.time.LocalDateTime;

LocalDate d = LocalDate.of(2024, 3, 15);
System.out.println(d.plusDays(10));    // 2024-03-25
System.out.println(d.plusMonths(2));   // 2024-05-15
System.out.println(d.minusYears(1));  // 2023-03-15

// 月末の調整
LocalDate jan31 = LocalDate.of(2024, 1, 31);
System.out.println(jan31.plusMonths(1)); // 2024-02-29（閏年）

LocalDate jan31b = LocalDate.of(2023, 1, 31);
System.out.println(jan31b.plusMonths(1)); // 2023-02-28（平年）

// メソッドチェーン
LocalDate result = d.plusDays(5).plusMonths(1).minusYears(2);
System.out.println(result); // 2022-04-20

import java.time.LocalDate;
import java.time.temporal.TemporalAdjusters;
import java.time.DayOfWeek;

LocalDate d = LocalDate.of(2024, 3, 15);

// withメソッド
System.out.println(d.withDayOfMonth(1));  // 2024-03-01
System.out.println(d.withMonth(6));       // 2024-06-15
System.out.println(d.withYear(2025));     // 2025-03-15

// TemporalAdjusters
System.out.println(d.with(TemporalAdjusters.firstDayOfMonth()));  // 2024-03-01
System.out.println(d.with(TemporalAdjusters.lastDayOfMonth()));   // 2024-03-31
System.out.println(d.with(TemporalAdjusters.next(DayOfWeek.MONDAY))); // 次の月曜
System.out.println(d.with(TemporalAdjusters.firstDayOfNextMonth())); // 2024-04-01

import java.time.*;

// Period（年月日の期間）
Period p1 = Period.of(1, 2, 3);  // 1年2ヶ月3日
Period p2 = Period.ofMonths(6);   // 6ヶ月
Period p3 = Period.between(
    LocalDate.of(2024, 1, 1),
    LocalDate.of(2024, 4, 15)
); // 3ヶ月14日

LocalDate d = LocalDate.of(2024, 1, 1);
System.out.println(d.plus(p1)); // 2025-03-04

// Duration（時間の期間）
Duration d1 = Duration.ofHours(5);    // 5時間
Duration d2 = Duration.ofMinutes(90); // 90分
Duration d3 = Duration.between(
    LocalTime.of(10, 0),
    LocalTime.of(14, 30)
); // 4時間30分

LocalTime t = LocalTime.of(10, 0);
System.out.println(t.plus(d1)); // 15:00

// 型の不一致 → 例外
// LocalTime.now().plus(p1); // UnsupportedTemporalTypeException

